import sys
from collections import defaultdict

class Solution:
    def solve(self, graph):
        n, m = map(int, sys.stdin.readline().split())
        self.graph = defaultdict(list, graph)
        is_visited = [False] * n
        for i in range(n):
            if is_visited[i]:
                continue
            stack = [i]
            while stack:
                node = stack.pop()
                if is_visited[node]:
                    return True
                is_visited[node] = True
                for neighbor in self.graph[node]:
                    if not is_visited[neighbor]:
                        stack.append(neighbor)
        return False

solution = Solution()
output = solution.solve() and "true" or "false"
print(output)

