#include <iostream>
#include <vector>
#include <set>
#include <queue>
#include <string>
#include <sstream>

using namespace std;

class Solution {
public:
    bool solve(vector<vector<int>>& graph) {
        int n = graph.size();
        vector<bool> is_visited(n, false);
        for (int i = 0; i < n; i++) {
            if (is_visited[i]) {
                continue;
            }
            set<int> stack = {i};
            while (!stack.empty()) {
                int node = *stack.begin();
                stack.erase(stack.begin());
                if (is_visited[node]) {
                    return true;
                }
                is_visited[node] = true;
                for (auto neighbor : graph[node]) {
                    if (!is_visited[neighbor]) {
                        stack.insert(neighbor);
                    }
                }
            }
        }
        return false;
    }
};

int main() {
    Solution solution;
    int n, m;
    cin >> n >> m;
    vector<vector<int>> graph(n);
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        graph[u].push_back(v);
        graph[v].push_back(u);
    }
    cout << (solution.solve(graph) ? "true" : "false") << endl;
    return 0;
}
